_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float ang2, c, s;
vUv -= .5;
vUv *= uAspect.xy;


uv2 = vec2(1/vRadius+uTime/2, vAngle*2/3.14);
float z = abs(.5/vUv.y);
uv2 = vec2(z*vUv.x, z+uTime/2);
vec2 noise = (texture(sampler_noise_hq,uv2)-.5)/z*2;
//vUv += vRadius*vRadius * noise*.02;

float dist = 1;
float bdist = 1;
float inten = 1;
ret1 = 0;
int anz = 1;
float n = 1;
while (n <= anz) {
    ang2 = n/anz*3.14+q9;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    uv3 = fract(1*uv2*dist + .5 );;

    uv3=abs(fract(uv3+.5)-.5) +vRadius*vRadius * noise*.02*audioLowSmooth;;
    bdist = (1-GetBlur2(uv3).b);
    uv4 = multiply(uv3,mat2(cos(q31),sin(q31), -sin(q31), cos(q31))),
    sun = .04/length(sin(uv4.x*audioLowSmooth+1.5+bdist+ noise*.04*audioLowSmooth))*bdist;
    arg = bdist + q6;
    neu =  mix(GetPixel (uv3).r,GetBlur1(uv3).r,clamp01(q11*8)*1.1) ;
    neu = max(neu,sun)*(bdist+.2)*(2+sin(vec3(arg*2, arg*3,5*arg)));
//    neu = mix(neu,sun/q11,clamp01(q11*18))*(bdist+.2)*(2+sin(vec3(arg*2, arg*3,5*arg)));
    ret1 = max(ret1*1,neu) ;
n++;
}
//ret = 1-exp(-ret1/2/(audioLow*.1+1*vRadius)+.1);
ret = 1-exp(-ret1/(.2/audioLow+vRadius)/audioLow*.5+.1);
//ret = GetPixel(vUv+.5).r;
//ret = sun;

  fragColor = ret;
}
